1	interface Item {
2	  type: string;
3	}
4	
5	interface Policy {
6	  items: Item[];
7	  customer: { yearsWithMHPCO: number };
8	  isFollowUp: boolean;
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25 };
14	const DEFAULT_BASE_PREMIUM = 60;
15	
16	export function quote(policy: Policy) {
17	  if (policy.items.length === 0) {
18	    return { premium: PROCESSING_FEE };
19	  }
20	  const basePremium = BASE_PREMIUM[policy.items[0].type] ?? DEFAULT_BASE_PREMIUM;
21	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
22	  return { premium: Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE) };
23	}
24	
25	export function claim() {
26	  return undefined;
27	}
